const { Parser } = require('json2csv');
const data = JSON.parse(inputData);
const rows = Array.isArray(data) ? data : [data];
outputData = new Parser().parse(rows);

const fn = getTransformer('ogc.bbr.examples.transforms.transforms-example', 'inline-transform');
const jqResult = fn(inputData);
const data = JSON.parse(jqResult);
data._processedBy = 'transforms-reuse/node-calls-jq (node → jq)';
outputData = JSON.stringify(data, null, 2);

const fn = getTransformer('ogc.bbr.examples.transforms.transforms-example', 'python-uppercase-keys');
const uppercased = fn(inputData);
const data = JSON.parse(uppercased);
data.PROCESSED_BY = 'transforms-reuse/node-calls-python (node → python)';
outputData = JSON.stringify(data, null, 2);

const fn = getTransformer('ogc.bbr.examples.transforms.transforms-reuse', 'reuse-jq-inline');
const result = fn(inputData);
const data = JSON.parse(result);
data._chain = 'node → python → jq';
outputData = JSON.stringify(data, null, 2);

def jsoncontext:  (         
         {
          "asJSON": {
            "@id": "param:asJSON",
            "@type": "@json"
          },
          "param": "https://w3id.org/ogc/api/processes/",
          "@version": 1.1

        } );


{ 
  "@id": (if .["@id"] then .["@id"] else .id end ),
   "@context": (

      if ."@context" | type == "array" then
        ."@context" + [ jsoncontext ]
      else
        ."@context" +  jsoncontext
      end
    ), 
   "asJSON": (. | del(."@context"))
}
